importScripts("collection-solver.min.js");
self.onmessage = (event) => {
const data = event.data || {};
if (data.type !== "solve" && data.type !== "validate") return;
try {
const input =
data.type === "validate"
? {
...(data.input || {}),
monteCarloRuns: Math.max(0, Math.floor(Number(data.runs) || 0)),
monteCarloSeed: Math.max(0, Math.floor(Number(data.seed) || 20260505)),
}
: data.input;
const result = self.CollectionSolver.solve(input, (progress) => {
self.postMessage({ type: "progress", id: data.id, progress });
});
self.postMessage({
type: "result",
id: data.id,
result: data.type === "validate" ? result.monteCarlo : result,
});
} catch (error) {
self.postMessage({
type: "error",
id: data.id,
message: error && error.message ? error.message : String(error),
});
}
};
